      ('fea4dc04-fd53-4120-b7e8-3e8a48d35c8e'::uuid,'فيلا العارض','Residential','Medium (1,000-10,000 m²)','Foundation Works / Substructure','النرجس','https://maps.app.goo.gl/9nnsuTvmcP2aiDay8','SAL-0024-001','2026-01-18 14:15:59.707376+00'::timestamptz,'2026-01-28 19:13:15.356668+00'::timestamptz),
      ('eb2cff71-b224-48f3-8693-0a418c23f316'::uuid,'فيلا النرجس','Residential','Small (100-1,000 m²)','Foundation Works / Substructure','النرجس','https://maps.app.goo.gl/ps2YZPX3vpdLQWoC7','SAL-0007-001','2026-01-17 10:49:52.082769+00'::timestamptz,'2026-01-28 19:13:15.356668+00'::timestamptz),
      ('3b5254d0-c1fc-4a3a-94b2-f9229550c09c'::uuid,'فيلا العارض','Residential','Small (100-1,000 m²)','Skeleton Works / Superstructure','العارض','24.8791601,46.611909','SAL-0087-001','2026-01-30 18:33:28.861118+00'::timestamptz,'2026-01-30 18:33:28.861118+00'::timestamptz),
      ('4938a4a3-1630-4ae3-b251-1b2c6ba13bf9'::uuid,'فيلل العارض','Residential','Small (100-1,000 m²)','Skeleton Works / Superstructure','العارض','','SAL-0131-001','2026-01-30 18:42:09.311721+00'::timestamptz,'2026-01-30 18:42:09.311721+00'::timestamptz),
      ('46583c2b-99b3-45af-846c-4c2db82065ff'::uuid,'عماير العارض','Residential','Small (100-1,000 m²)','Foundation Works / Substructure','العارض','24.8773046,46.614875','SAL-0135-001','2026-01-30 18:52:01.989621+00'::timestamptz,'2026-01-30 18:52:01.989621+00'::timestamptz),
      ('35936ca4-909b-41ba-a76d-03f57897ed89'::uuid,'عماره العارض','Residential','Small (100-1,000 m²)','Finishing Works','العارض','','SAL-0136-001','2026-01-30 18:53:28.660496+00'::timestamptz,'2026-01-30 18:53:28.660496+00'::timestamptz),
      ('43afa2b8-0fd2-434b-b2b6-8b70a1d3c38f'::uuid,'عماره العارض','Residential','Small (100-1,000 m²)','Finishing Works','العارض','','SAL-0156-001','2026-01-30 19:05:49.635509+00'::timestamptz,'2026-01-30 19:05:49.635509+00'::timestamptz),
      ('19a7b9f6-0e1e-4c1a-8ee3-aaa333333301'::uuid,'فيلل النرجس','Residential','Small (100-1,000 m²)','Masonry & MEP Works','النرجس','https://maps.app.goo.gl/eaX7yTBV39yuejY69','SAL-0011-001','2026-01-17 11:22:09.000000+00'::timestamptz,'2026-01-28 19:13:15.356668+00'::timestamptz)
    ) AS t(id, name, project_type, project_size, current_phase, district, location_raw, project_code, created_at, updated_at)
  LOOP
    -- Extract customer code: SAL-0086-001 → SAL.0086
    v_cust_num := split_part(replace(r.project_code, 'SAL-', ''), '-', 1);
    v_proj_num := split_part(replace(r.project_code, 'SAL-', ''), '-', 2);
    v_cust_code := 'SAL.' || LPAD(v_cust_num, 4, '0');
    v_new_code := v_cust_code || '_' || v_proj_num;
    
    -- Find account
    SELECT id INTO v_acct_id FROM accounts WHERE code = v_cust_code;
    IF v_acct_id IS NULL THEN
      RAISE NOTICE 'Skipping project % - no account found for %', r.project_code, v_cust_code;
      CONTINUE;
    END IF;
    
    -- Parse location
    v_lat := NULL; v_lng := NULL; v_addr_link := NULL;
    v_district := NULLIF(TRIM(r.district), '');
    v_addr_text := CASE 
      WHEN v_district IS NOT NULL THEN 'حي ' || v_district || '، الرياض'
      ELSE 'الرياض'
    END;
    
    IF r.location_raw ~ '^\d+\.?\d*,' THEN
      -- Raw lat,lng coordinates
      v_lat := split_part(r.location_raw, ',', 1)::numeric;
      v_lng := split_part(r.location_raw, ',', 2)::numeric;
      v_addr_link := 'https://www.google.com/maps?q=' || v_lat || ',' || v_lng;
    ELSIF r.location_raw LIKE 'http%' THEN
      -- Google Maps link
      v_addr_link := r.location_raw;
    END IF;
    
    -- Create location (PostGIS trigger auto-detects zone_code for lat/lng)
    INSERT INTO locations (city, country, region_code, lat, lng, address_text, address_link)
    VALUES ('Riyadh'::saudi_city, 'SA'::gcc_country, 'RYD', v_lat, v_lng, v_addr_text, v_addr_link)
    RETURNING id INTO v_loc_id;
    
    -- Create project
    INSERT INTO projects (id, customer_account_id, name, project_type, project_size, 
                          current_phase, location_id, code, metadata, created_at, updated_at)
    VALUES (r.id, v_acct_id, r.name, r.project_type, r.project_size,
            r.current_phase, v_loc_id, v_new_code, '{}'::jsonb, r.created_at, r.updated_at)
    ON CONFLICT (id) DO NOTHING;
  END LOOP;
  
  -- Flag all projects where zone was NOT detected as needs_review
  UPDATE projects p
  SET metadata = jsonb_set(
    COALESCE(p.metadata, '{}'),
    '{needs_review}',
    '"location: no zone detected - requires manual coordinate verification"'
  )
  FROM locations l
  WHERE l.id = p.location_id AND l.zone_code IS NULL;
  
END;
$$;
